import React from 'react';
import Navbar from '@/src/components/Navbar';
import MovieSection from '@/src/components/MovieSection';
import Footer from '@/src/components/Footer';
import { INITIAL_MOVIES } from '@/src/constants';
import { pool } from '@/src/lib/db';

export const dynamic = 'force-dynamic';

async function getMovies() {
  try {
    // Use a raw SQL query on the pool (e.g. pg or mysql) since Pool has no `movies` property.
    const result: any = await pool.query('SELECT * FROM movies ORDER BY "createdAt" DESC');
    const movies = result?.rows ?? result?.[0] ?? [];

    return movies.length > 0 ? movies : INITIAL_MOVIES;
  } catch (error) {
    console.error('Error fetching movies:', error);
    return INITIAL_MOVIES;
  }
}

export default async function Home() {
  const movies = await getMovies();

  return (
    <div className="min-h-screen font-sans selection:bg-[#e5a00d] selection:text-black">
      <Navbar />

      <main className="p-4">
        {/* Movie sections only */}
        <MovieSection
          title="Movies To Watch Right Now"
          movies={movies.slice(0, 4) as any}
          type="video"
        />

    

        <MovieSection
          title="Binge-Worthy Shows"
          movies={movies as any}
          type="poster"
        />

        <MovieSection
          title="And The Winner Was"
          movies={[...movies].reverse() as any}
          type="poster"
        />

        <Footer />
      </main>
    </div>
  );
}